    return featureSet.map((value, index) => {
        let column = features.map(row => row[index]);
        let mean = column.reduce((a, b) => a + b, 0) / column.length;
        let std = Math.sqrt(column.map(x => Math.pow(x - mean, 2)).reduce((a, b) => a + b) / column.length);
        return (value - mean) / std;
    });
});

