async function connect() {
    try {
        const connection = await amqp.connect('amqp://pavlos:loco21959@localhost');
        const channel = await connection.createChannel();

        const queue = user.username;
        await channel.assertQueue(queue, { durable: true });

        global.set(`amqpConnection${queue}`,{ connection,channel });


        console.log(`Waiting for messages in ${queue}`);
        channel.consume(queue, (msg) => {
            if (msg !== null) {
                let content;

            // Check if msg.content is a Buffer
            if (Buffer.isBuffer(msg.content)) {
                content = msg.content.toString(); // Convert buffer to string
            } else {
                content = msg.content; // Already an object or string
            }

            // Parse the content if it's a JSON string
            let parsedContent;
            try {
                parsedContent = typeof content === 'string' ? JSON.parse(content) : content;
            } catch (err) {
                console.error("Failed to parse JSON:", content);
                parsedContent = { rawContent: content }; // Preserve raw content if parsing fails
            }
            // msg.payload.content = parsedContent
            // msg.payload.queueName = queue;
            msg.queue = queue;
            msg.payload = parsedContent;
            node.send(msg);
            }
        });

    } catch (err) {
        console.error(err);
    }
}

