        const path = req.url; // Get the URL path (e.g., /ws/user1)
        node.warn(path);
        // Add the client to the appropriate group based on path
        if (!clientsByPath.has(path)) {
            clientsByPath.set(path, []);
        }
        clientsByPath.get(path).push(socket);

        node.warn(`New client connected on path: ${path}`);

        // Listen for incoming messages
        socket.on('message', (message) => {
            node.warn(`Message from ${path}: ${message}`);
        });



        // Handle client disconnection
        socket.on('close', () => {
            node.warn(`Client disconnected from path: ${path}`);
            clientsByPath.set(
