async function publishMessage( routingKey, message) {
    try {
        // 1. Connect to RabbitMQ server
        const connection = await amqp.connect('amqp://pavlos:loco21959@localhost:5672');
        const channel = await connection.createChannel();

        // 2. Define the exchange and routing key or queue
        const exchange = 'air_quality_notifications';


        // 3. Ensure exchange exists
        await channel.assertExchange(exchange, 'topic', { durable: true });

        // 4. Publish the message
        channel.publish(exchange, routingKey, Buffer.from(message), {
            persistent: true, // Ensures the message survives broker restarts
        });
        console.log(`Message published to exchange "${exchange}" with routing key "${routingKey}"`);

        // 5. Close the connection
        await channel.close();
        await connection.close();
    } catch (error) {
        console.error('Failed to publish message:', error);
    }
}

