if (!global.get('wsServer')) {
    const wsServer = new WebSocket.Server({ port: 8080 });

    // Store the server in the global context
    global.set('wsServer', wsServer);

    // Create a map to store clients by path
    const clientsByPath = new Map();
    global.set('clientsByPath', clientsByPath);

    wsServer.on('connection', (socket, req) => {
        const path = req.url; // Get the URL path (e.g., /ws/user1)
        node.warn(path);
        // Add the client to the appropriate group based on path
        if (!clientsByPath.has(path)) {
            clientsByPath.set(path, []);
        }
        clientsByPath.get(path).push(socket);

        node.warn(`New client connected on path: ${path}`);

        // Listen for incoming messages
        socket.on('message', (message) => {
            node.warn(`Message from ${path}: ${message}`);
        });

        // Handle client disconnection
        socket.on('close', () => {
            node.warn(`Client disconnected from path: ${path}`);
            clientsByPath.set(
                path,
                clientsByPath.get(path).filter((client) => client !== socket)
            );
        });

        // Send a welcome message to the client
        socket.send(JSON.stringify({ message: `Welcome to ${path}!` }));
    });

    node.warn('WebSocket server started on port 8080');
}

