const wsServer = global.get('wsServer');
const clientsByPath = global.get('clientsByPath');

// Handle client connections
wsServer.on('connection', (socket, req) => {
    const path = req.url; // E.g., /ws/user1 or /ws/user2
    node.warn(`New client connected on path: ${path}`);

    // Add the client to the appropriate group
    if (!clientsByPath.has(path)) {
        clientsByPath.set(path, []);
    }
    clientsByPath.get(path).push(socket);

    // Handle disconnection
    socket.on('close', () => {
        node.warn(`Client disconnected from path: ${path}`);
        const clients = clientsByPath.get(path) || [];
        const updatedClients = clients.filter((client) => client !== socket);
        if (updatedClients.length > 0) {
            clientsByPath.set(path, updatedClients);
        } else {
            clientsByPath.delete(path); // Remove empty paths
        }
    });

    // Handle messages from the client
    socket.on('message', (message) => {
        node.warn(`Message received from ${path}: ${message}`);
    });

    // Send a welcome message to the client
    socket.send(JSON.stringify({ message: `Welcome to ${path}!` }));
});

